/**
 * A volatile ORDER BY expression must produce a stable ordering key per solution occurrence for the duration of the
 * sort: evaluating the expression inside the comparator gives the same row different keys during one sort, violating
 * the comparator's reflexivity/transitivity contract. The stable-key contract is an implementation technique — SPARQL
 * does not expose a call count — but the internal mechanism regression below pins that keys are no longer computed
 * inside {@code compare()}. A query-fatal error raised by an ordering expression (for example a failing non-silent
 * SERVICE inside EXISTS) must fail the query, never silently sort as "equal".
 */
public class MemoryVolatileOrderByTest {

	private SailRepository repository;
	private CountingVolatileFunction canary;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new MemoryStore());
		repository.init();
		canary = new CountingVolatileFunction();
		FunctionRegistry.getInstance().add(canary);
	}

	@AfterEach
	public void tearDown() {
		FunctionRegistry.getInstance().remove(canary);
		repository.shutDown();
	}

	private List<BindingSet> evaluate(String query) {
		try (RepositoryConnection connection = repository.getConnection()) {
			return QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
		}
	}

	/**
	 * Internal mechanism regression: the ordering key of a volatile expression is established once per solution
	 * occurrence, not once per comparison. (An exact call count is asserted only because this pins the internal
	 * mechanism — it is not a SPARQL conformance criterion.)
	 */
	@Test
	public void volatileOrderKeyIsEvaluatedOncePerSolution() {
		List<BindingSet> rows = evaluate(
				"SELECT ?x WHERE { VALUES ?x { 1 2 3 4 5 } } ORDER BY <" + CountingVolatileFunction.URI + ">()");

		assertEquals(5, rows.size());
		assertEquals(5, distinct(rows, "x").size(), "every input occurrence appears exactly once");
		assertEquals(5, canary.calls.get(),
				"the ordering key is established once per solution occurrence, not per comparison");
	}

	/** The result of a volatile ordering is a permitted ordering: a permutation of the input multiset. */
	@Test
	public void volatileOrderReturnsPermutation() {
		List<BindingSet> rows = evaluate("SELECT ?x WHERE { VALUES ?x { 1 2 3 4 5 } } ORDER BY RAND()");

		assertEquals(5, rows.size());
		assertEquals(5, distinct(rows, "x").size());
	}

	/** Stored key state must survive spilling to disk without re-evaluation. */
	@Test
	public void volatileOrderWithSpillReturnsAllRowsOnce() {
		((MemoryStore) repository.getSail()).setIterationCacheSyncThreshold(2);

		List<BindingSet> rows = evaluate(
				"SELECT ?x WHERE { VALUES ?x { 1 2 3 4 5 6 7 8 } } ORDER BY <" + CountingVolatileFunction.URI
						+ ">()");

		assertEquals(8, rows.size());
		assertEquals(8, distinct(rows, "x").size());
		assertEquals(8, canary.calls.get(), "spilled key state is replayed, never re-evaluated");
	}

	/** A query-fatal error from an ordering expression fails the query instead of sorting as "equal". */
	@Test
	public void fatalErrorInOrderExpressionFailsQuery() {
		repository.setFederatedServiceResolver(serviceUrl -> new FailingService());

		assertThrows(QueryEvaluationException.class,
				() -> evaluate("SELECT ?x WHERE { VALUES ?x { 1 2 } } "
						+ "ORDER BY EXISTS { SERVICE <urn:fail> { ?s ?p ?o } }"));
	}

	private static Set<Value> distinct(List<BindingSet> rows, String name) {
		Set<Value> values = new HashSet<>();
		for (BindingSet row : rows) {
			values.add(row.getValue(name));
		}
		return values;
	}

	private static final class CountingVolatileFunction implements Function {

		private static final String URI = "urn:test:volatile-order-key";

		private final AtomicInteger calls = new AtomicInteger();

		@Override
		public String getURI() {
			return URI;
		}

		@Override
		public Value evaluate(ValueFactory valueFactory, Value... args) {
			return valueFactory.createLiteral(calls.incrementAndGet());
		}
	}

	private static final class FailingService implements FederatedService {

		private boolean initialized;

		@Override
		public boolean ask(Service service, BindingSet bindings, String baseUri) {
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public CloseableIteration<BindingSet> select(Service service, Set<String> projectionVars,
				BindingSet bindings, String baseUri) {
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public CloseableIteration<BindingSet> evaluate(Service service, CloseableIteration<BindingSet> bindings,
				String baseUri) {
			if (!bindings.hasNext()) {
				bindings.close();
				return new EmptyIteration<>();
			}
			bindings.close();
			throw new QueryEvaluationException("service unavailable");
		}

		@Override
		public boolean isInitialized() {
			return initialized;
		}

		@Override
		public void initialize() {
			initialized = true;
		}

		@Override
		public void shutdown() {
			initialized = false;
		}
	}
}
